mapper.select:
SELECT COUNT(*)
FROM message_comment
WHERE message_id = #{messageId}

SELECT , CASE WHEN mc.is_anonymous = 1 THEN '匿名用户' ELSE u.username END AS username, CASE WHEN mc.is_anonymous = 1 THEN NULL ELSE u.avatar_url END AS avatar_url, CASE WHEN mc.parent_id IS NOT NULL THEN CASE WHEN parent_mc.is_anonymous = 1 THEN '匿名用户' ELSE parent_u.username END ELSE NULL END AS parent_username FROM message_comment mc LEFT JOIN user u ON mc.user_id = u.id LEFT JOIN message_comment parent_mc ON mc.parent_id = parent_mc.id LEFT JOIN user parent_u ON parent_mc.user_id = parent_u.id
AND (u.username LIKE CONCAT('%', #{username}, '%') OR (mc.parent_id IS NOT NULL AND parent_u.username LIKE CONCAT('%', #{username}, '%')))
ORDER BY mc.create_time DESC LIMIT #{pageSize} OFFSET #{offset}
